package com.ecoPedal.backend.entity;import jakarta.persistence.*;import lombok.Getter;import lombok.Setter;import lombok.NoArgsConstructor;import lombok.AllArgsConstructor;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Table(name = "recompense")public class Recompense {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false)    private String nom;    private String description;    @Column(nullable = false)    private Integer coutPoints;    @ManyToOne    @JoinColumn(name = "id_administrateur", nullable = false)    private Administrateur administrateur;}